const fs = require('fs');
const path = require('path');

const filesToFix = [
    'src/app/api/project/[id]/active-plan/route.ts',
    'src/app/api/project/[id]/plan/route.ts',
    'src/app/api/project/[id]/report/route.ts',
    'src/app/api/project/[id]/tasks/route.ts',
    'src/app/pm/project/[id]/page.tsx',
    'src/app/sm/project/[id]/plan/page.tsx',
    'src/app/sm/project/[id]/report/page.tsx'
];

for (const relPath of filesToFix) {
    const p = path.join('C:\\Users\\Imam\\.gemini\\antigravity\\scratch\\worksite-tracker', relPath);
    let content = fs.readFileSync(p, 'utf8');

    // Replace route handlers
    content = content.replace(/export async function (GET|POST)\(req: Request, \{ params \}: \{ params: \{ id: string \} \}\) \{/g,
        'export async function $1(req: Request, { params }: { params: Promise<{ id: string }> }) {\n  const resolvedParams = await params;\n  const id = resolvedParams.id;');

    // Replace page handlers
    content = content.replace(/export default (async )?function ([a-zA-Z0-9_]+)\(\{ params \}: \{ params: \{ id: string \} \}\) \{/g,
        'export default async function $2({ params }: { params: Promise<{ id: string }> }) {\n  const resolvedParams = await params;\n  const id = resolvedParams.id;');

    // Replace params.id with id
    content = content.replace(/params\.id/g, 'id');

    fs.writeFileSync(p, content);
}

