import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { verifyToken } from '@/lib/auth';

export async function POST(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const token = req.headers.get('cookie')?.split('auth-token=')[1]?.split(';')[0];
        if (!token) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const payload = await verifyToken(token) as any;
        if (!payload || payload.role !== 'ADMIN') {
            return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
        }

        const resolvedParams = await params;
        const userId = resolvedParams.id;
        
        const { action } = await req.json(); // "APPROVE" or "REJECT"

        if (action !== 'APPROVE' && action !== 'REJECT') {
            return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
        }

        const newStatus = action === 'APPROVE' ? 'APPROVED' : 'REJECTED';

        const updatedUser = await prisma.user.update({
            where: { id: userId },
            data: { status: newStatus }
        });

        return NextResponse.json({ success: true, status: updatedUser.status });
    } catch (err: any) {
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { verifyToken } from '@/lib/auth';

export async function GET(req: Request) {
    try {
        const token = req.headers.get('cookie')?.split('auth-token=')[1]?.split(';')[0];
        if (!token) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

        const payload = await verifyToken(token) as any;
        if (!payload || payload.role !== 'ADMIN') {
            return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
        }

        const users = await prisma.user.findMany({
            where: {
                role: { not: 'ADMIN' }
            },
            orderBy: {
                createdAt: 'desc'
            },
            select: {
                id: true,
                name: true,
                email: true,
                role: true,
                status: true,
                createdAt: true
            }
        });

        return NextResponse.json({ users });
    } catch (err: any) {
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import bcrypt from 'bcryptjs';

export async function POST(req: Request) {
    try {
        const { name, email, password, role } = await req.json();

        if (!email || !password || !role) {
            return NextResponse.json({ error: 'Tous les champs obligatoires doivent être remplis' }, { status: 400 });
        }

        const existingUser = await prisma.user.findUnique({
            where: { email }
        });

        if (existingUser) {
            return NextResponse.json({ error: 'Cette adresse e-mail est déjà utilisée' }, { status: 400 });
        }

        const passwordHash = await bcrypt.hash(password, 10);

        // Created with default status = "PENDING" automatically by prisma schema
        await prisma.user.create({
            data: {
                name,
                email,
                passwordHash,
                role
            }
        });

        return NextResponse.json({ success: true, message: 'Compte créé et en attente d\'approbation' });

    } catch (err: any) {
        console.error("Register Error:", err);
        return NextResponse.json({ error: 'Erreur interne du serveur' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
