"use client";
import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Lock } from 'lucide-react';

export default function LoginPage() {
    const router = useRouter();
    const [email, setEmail] = useState('pm@worksite.com'); // Autofill for convenience
    const [password, setPassword] = useState('password');
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setErrorMsg('');

        try {
            const res = await fetch('/api/auth/login', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email, password })
            });

            const data = await res.json();

            if (!res.ok) {
                setErrorMsg(data.error || 'Identifiants incorrects');
                setLoading(false);
                return;
            }

            if (data.success) {
                if (data.role === 'ADMIN') {
                    router.push('/admin/dashboard');
                } else if (data.role === 'PM') {
                    router.push('/pm/dashboard');
                } else {
                    router.push('/sm/dashboard');
                }
            }

        } catch (err) {
            setErrorMsg('Erreur de connexion au serveur.');
            setLoading(false);
        }
    };

    return (
        <div className="container min-h-screen flex items-center justify-center">
            <div className="glass-panel w-full max-w-[420px]">
                <div className="text-center mb-8">
                    <div className="w-12 h-12 rounded-full bg-blue-500/10 flex items-center justify-center mx-auto mb-4">
                        <Lock size={24} color="var(--accent-primary)" />
                    </div>
                    <h2>Bon retour</h2>
                    <p className="mt-2">Connectez-vous pour gérer vos chantiers.</p>
                </div>

                {errorMsg && (
                    <div className="bg-red-500/10 text-red-500 p-3 rounded mb-4 text-center border border-red-500/20">
                        {errorMsg}
                    </div>
                )}

                <form onSubmit={handleLogin}>
                    <div className="form-group">
                        <label htmlFor="emailInput" className="form-label">Adresse e-mail</label>
                        <input
                            id="emailInput"
                            type="email"
                            className="form-input"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label htmlFor="passwordInput" className="form-label">Mot de passe</label>
                        <input
                            id="passwordInput"
                            type="password"
                            className="form-input"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group mt-8">
                        <button type="submit" className="btn btn-primary w-full" disabled={loading}>
                            {loading ? 'Connexion en cours...' : 'Se Connecter'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

