                                    {plan.isSubmitted && !plan.targetReached && <span className="badge badge-danger flex items-center gap-1" style={{ background: 'var(--danger-glow)', color: 'var(--danger)' }}><ShieldAlert size={12} /> <T k="target_missed" /></span>}
