                            {/* Analytics details */}
                            {plan.isSubmitted && (
                                <div style={{ background: 'var(--bg-tertiary)', padding: '1rem', borderRadius: 'var(--radius-md)' }}>
                                    {plan.issuesReported ? (
                                        <>
                                            <div className="text-sm font-semibold mb-2"><T k="reported_issues" />:</div>
                                            <div className="text-sm text-secondary italic">"{plan.issuesReported}"</div>
                                        </>
                                    ) : (
                                        <div className="text-sm text-secondary italic"><T k="no_issues" /></div>
                                    )}
                                </div>
                            )}

                            <hr style={{ borderColor: 'var(--border-subtle)', margin: '0.5rem 0' }} />
                            <div>
                                <div className="text-sm font-semibold mb-2 flex items-center gap-2"><FileText size={16} /> <T k="scheduled_tasks" /></div>
                                <div className="flex flex-col gap-2">
                                    {plan.tasks.map((pt: any) => (
                                        <div key={pt.id} className="flex flex-col gap-2 p-2" style={{ background: 'rgba(255,255,255,0.02)', borderRadius: 'var(--radius-sm)' }}>
                                            <div className="flex justify-between items-center text-sm">
                                                <span><T dataText={pt.task.description} /></span>
                                                <div>
                                                    <span className="text-secondary"><T k="planned" />: {pt.plannedQuantity} <T k={pt.task.unit} /></span>
                                                    {plan.isSubmitted && <span className="ml-4 font-semibold"><T k="done" />: {pt.actualQuantity}</span>}
                                                </div>
                                            </div>
                                            {pt.photos && pt.photos.length > 0 && (
                                                <div className="mt-2 flex gap-2 overflow-x-auto pb-2">
                                                    {pt.photos.map((photo: any) => (
                                                        <img 
                                                            key={photo.id} 
                                                            src={photo.url} 
                                                            alt={photo.caption || "Proof"} 
                                                            style={{ height: '80px', borderRadius: '4px', objectFit: 'cover' }} 
                                                        />
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </main>
        </>
    );
}

