"use client";

import React, { useMemo, useState } from 'react';
import { PieChart, Pie, Cell, Tooltip as PieTooltip, ResponsiveContainer, CartesianGrid, XAxis, YAxis, Tooltip as BarTooltip, LineChart, Line, BarChart, Bar } from 'recharts';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { useTranslation } from '@/lib/LanguageContext';

export default function ProjectAnalyticsCharts({ tasks, weeklyPlans }: { tasks: any[], weeklyPlans: any[] }) {
    const { t, tData } = useTranslation();
    const [weeksToShow, setWeeksToShow] = useState<number>(0); // 0 = all
    const [startIndex, setStartIndex] = useState<number>(0);

    // 1. Prepare Pie Chart Data (Hours per Category)
    const pieData = useMemo(() => {
        const catMap: Record<string, number> = {};
        let totalHours = 0;

        tasks.forEach(t => {
            const hrs = (t.quantity * t.minutesPerUnit) / 60;
            const cat = t.category || "Autre";
            catMap[cat] = (catMap[cat] || 0) + hrs;
            totalHours += hrs;
        });

        const threshold = totalHours * 0.02; // 2% 
        let finalData: any[] = [];
        let othersHours = 0;

        Object.entries(catMap).forEach(([name, value]) => {
            if (value > threshold) {
                finalData.push({ name: tData(name), value });
            } else {
                othersHours += value;
            }
        });

        if (othersHours > 0) {
            finalData.push({ name: t("others"), value: othersHours });
        }

        return finalData.sort((a, b) => b.value - a.value);
    }, [tasks, t, tData]);

    const COLORS = ['#F59E0B', '#10B981', '#3B82F6', '#6366F1', '#8B5CF6', '#EC4899', '#F43F5E', '#14B8A6', '#84CC16', '#64748B'];

    const getCategoryIcon = (catName: string) => {
        const lower = catName.toLowerCase();
        if (lower.includes('câble') || lower.includes('chemin') || lower.includes('treillis')) return '/categories/cable.png';
        if (lower.includes('tableau') || lower.includes('coffret') || lower.includes('commut') || lower.includes('cc / cv')) return '/categories/panel.png';
        if (lower.includes('eclairage') || lower.includes('eclairage') || lower.includes('luminaire')) return '/categories/light.png';
        if (lower.includes('equipement') || lower.includes('appareillage') || lower.includes('prise')) return '/categories/plug.png';
        if (lower.includes('astrid') || lower.includes('réseau') || lower.includes('donnée')) return '/categories/network.png';
        return '/categories/generic.png';
    };

    // 2. Prepare Progression Chart Data (Weekly Planned vs Executed)
    const lineData = useMemo(() => {
        const sortedPlans = [...weeklyPlans].sort((a, b) => {
            if (a.year !== b.year) return a.year - b.year;
            return a.weekNumber - b.weekNumber;
        });

        return sortedPlans.map(plan => {
            let plannedHrs = 0;
            let executedHrs = 0;

            plan.tasks.forEach((pt: any) => {
                const minsPerUnit = pt.task?.minutesPerUnit || 0;
                plannedHrs += (pt.plannedQuantity * minsPerUnit) / 60;
                executedHrs += (pt.actualQuantity * minsPerUnit) / 60;
            });

            // Very simple week-to-month approximation mapping for visualization
            // Week 1 -> Jan, Week 5 -> Feb, Week 9 -> Mar...
            const monthNames = ["Jan", "Fév", "Mar", "Avr", "Mai", "Juin", "Juil", "Aoû", "Sep", "Oct", "Nov", "Déc"];
            let approxMonthIdx = Math.floor((plan.weekNumber - 1) / 4.33);
            if (approxMonthIdx > 11) approxMonthIdx = 11;
            const monthLabel = monthNames[approxMonthIdx];

            return {
                name: `S${plan.weekNumber} (${monthLabel})`,
                [t("planned")]: Number(plannedHrs.toFixed(1)),
                [t("executed")]: Number(executedHrs.toFixed(1)),
            };
        });
    }, [weeklyPlans, t]);

    const displayLineData = useMemo(() => {
        if (weeksToShow === 0) return lineData;
        const start = Math.max(0, startIndex);
        return lineData.slice(start, start + weeksToShow);
    }, [lineData, weeksToShow, startIndex]);

    const handleNext = () => {
        if (startIndex + weeksToShow < lineData.length) {
            setStartIndex(s => s + weeksToShow);
        }
    };
    
    const handlePrev = () => {
        if (startIndex - weeksToShow >= 0) {
            setStartIndex(s => s - weeksToShow);
        } else {
            setStartIndex(0);
        }
    };

    // 3. Prepare Heatmap Data (Planned vs Executed per Category)
    const heatmapData = useMemo(() => {
        const catMap: Record<string, { planned: number, executed: number }> = {};
        
        // Sum planned and executed hours per task from all plans
        weeklyPlans.forEach(plan => {
            plan.tasks.forEach((pt: any) => {
                const cat = pt.task?.category || "Autre";
                const minsPerUnit = pt.task?.minutesPerUnit || 0;
                
                if (!catMap[cat]) catMap[cat] = { planned: 0, executed: 0 };
                catMap[cat].planned += (pt.plannedQuantity * minsPerUnit) / 60;
                catMap[cat].executed += (pt.actualQuantity * minsPerUnit) / 60;
            });
        });

        // Filter out categories with 0 planned and 0 executed
        return Object.entries(catMap)
            .map(([name, data]) => ({
                name: tData(name),
                [t("planned")]: Number(data.planned.toFixed(1)),
                [t("executed")]: Number(data.executed.toFixed(1)),
            }))
            .filter(item => item[t("planned")] > 0 || item[t("executed")] > 0)
            .sort((a, b) => b[t("planned")] - a[t("planned")]);
    }, [weeklyPlans, t, tData]);

    return (
        <div className="grid grid-cols-2 gap-8 mb-8">
            <div className="glass-card neon-card-blue flex flex-col" style={{ height: '400px' }}>
                <h3 className="mb-4">{t("hour_distribution")}</h3>
                <div className="flex-1 flex overflow-hidden min-h-0 min-w-0 items-center">
                    <div className="w-1/2 relative h-full min-h-0 min-w-0 flex items-center justify-center">
                        {pieData.length > 0 ? (
                            <ResponsiveContainer width="99%" height="99%">
                                <PieChart>
                                    <Pie
                                    data={pieData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius="50%"
                                    outerRadius="80%"
                                    paddingAngle={2}
                                    dataKey="value"
                                    stroke="none"
                                >
                                    {pieData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <PieTooltip formatter={(value: any) => `${Number(value).toFixed(0)} ${t("hours")}`} contentStyle={{ backgroundColor: 'rgba(0,0,0,0.8)', border: '1px solid var(--accent-primary)', borderRadius: '8px', color: 'white' }} />
                                </PieChart>
                            </ResponsiveContainer>
                        ) : (
                            <div className="text-secondary">{t("no_data")}</div>
                        )}
                    </div>
                    
                    <div className="w-1/2 h-full overflow-y-auto pr-2 custom-scrollbar flex flex-col gap-3 justify-center">
                        {pieData.map((entry, idx) => {
                            const percent = (pieData.reduce((acc, curr) => acc + curr.value, 0) > 0) ? ((entry.value / pieData.reduce((acc, curr) => acc + curr.value, 0)) * 100).toFixed(1) : 0;
                            return (
                                <div key={entry.name} className="flex items-center gap-3 p-2 rounded bg-white/5 border border-white/10 hover:border-white/20 transition-colors">
                                    <div className="rounded-md overflow-hidden flex-shrink-0 border flex items-center justify-center bg-black" style={{ width: '40px', height: '40px', borderColor: COLORS[idx % COLORS.length]}}>
                                        <img src={getCategoryIcon(entry.name)} alt={entry.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="text-sm font-medium text-white truncate" title={entry.name}>{entry.name}</div>
                                        <div className="text-xs text-secondary flex items-center gap-2">
                                            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></span>
                                            {percent}% ({Number(entry.value).toFixed(0)}h)
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            <div className="glass-card neon-card-green" style={{ height: '400px', display: 'flex', flexDirection: 'column' }}>
                <div className="flex justify-between items-center mb-4">
                    <h3>{t("efficiency_progression")}</h3>
                    
                    <div className="flex items-center gap-4">
                        <select 
                            className="bg-transparent text-secondary border border-gray-700 rounded p-1 text-sm outline-none"
                            value={weeksToShow}
                            onChange={(e) => {
                                setWeeksToShow(Number(e.target.value));
                                setStartIndex(0);
                            }}
                        >
                            <option value={0}>{t("all_weeks")}</option>
                            <option value={4}>{t("weeks_4")}</option>
                            <option value={8}>{t("weeks_8")}</option>
                            <option value={12}>{t("weeks_12")}</option>
                        </select>
                        
                        {weeksToShow > 0 && (
                            <div className="flex items-center gap-1">
                                <button className="btn btn-secondary p-1" onClick={handlePrev} disabled={startIndex === 0}><ChevronLeft size={16}/></button>
                                <span className="text-secondary text-sm mx-2">{t("display")}</span>
                                <button className="btn btn-secondary p-1" onClick={handleNext} disabled={startIndex + weeksToShow >= lineData.length}><ChevronRight size={16}/></button>
                            </div>
                        )}
                    </div>
                </div>
                
                <div style={{ flex: 1 }}>
                    <ResponsiveContainer width="100%" height="100%">
                        <LineChart data={displayLineData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
                            <XAxis dataKey="name" stroke="var(--text-secondary)" tick={{fontSize: 12}} />
                            <YAxis stroke="var(--text-secondary)" />
                            <BarTooltip
                                contentStyle={{ backgroundColor: 'var(--bg-tertiary)', border: 'none', borderRadius: 'var(--radius-md)' }}
                                itemStyle={{ color: 'var(--text-primary)' }}
                            />
                            <Line type="stepAfter" dataKey={t("planned")} stroke="var(--text-secondary)" strokeWidth={2} strokeDasharray="5 5" />
                            <Line type="monotone" dataKey={t("executed")} stroke="var(--accent-primary)" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                        </LineChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Heatmap Row */}
            <div className="col-span-2 glass-card neon-card-purple" style={{ height: '400px', display: 'flex', flexDirection: 'column' }}>
                <h3 className="mb-4">{t("category_heatmap")}</h3>
                <div style={{ flex: 1 }}>
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={heatmapData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" vertical={false} />
                            <XAxis dataKey="name" stroke="var(--text-secondary)" tick={{fontSize: 12}} />
                            <YAxis stroke="var(--text-secondary)" />
                            <BarTooltip
                                contentStyle={{ backgroundColor: 'var(--bg-tertiary)', border: 'none', borderRadius: 'var(--radius-md)' }}
                                itemStyle={{ color: 'var(--text-primary)' }}
                                cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                            />
                            <Bar dataKey={t("planned")} fill="var(--text-secondary)" radius={[4, 4, 0, 0]} />
                            <Bar dataKey={t("executed")} fill="var(--accent-primary)" radius={[4, 4, 0, 0]} />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </div>
        </div>
    );
}

import { SignJWT, jwtVerify } from 'jose';

const JWT_SECRET = process.env.JWT_SECRET || 'a-very-secure-secret-key-12345';
const encodedSecret = new TextEncoder().encode(JWT_SECRET);

export async function signToken(payload: any) {
    return await new SignJWT(payload)
        .setProtectedHeader({ alg: 'HS256' })
        .setIssuedAt()
        .setExpirationTime('24h')
        .sign(encodedSecret);
}

export async function verifyToken(token: string) {
    try {
        const { payload } = await jwtVerify(token, encodedSecret);
        return payload;
    } catch (e) {
        return null;
    }
}

export interface OfflineReport {
    id: string; // project id
    url: string;
    body: any; // The report payload
    photos: Record<string, string>; // base64 photos mapped by planTaskId
    timestamp: string;
}

const DB_NAME = 'worksite_offline_db';
const STORE_NAME = 'reports_store';

export async function initDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, 1);
        request.onupgradeneeded = () => {
            const db = request.result;
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME, { keyPath: 'timestamp' });
            }
        };
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function saveOfflineReport(report: OfflineReport): Promise<void> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readwrite');
        const store = tx.objectStore(STORE_NAME);
        const req = store.put(report);
        req.onsuccess = () => resolve();
        req.onerror = () => reject(req.error);
    });
}

export async function getOfflineReports(): Promise<OfflineReport[]> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readonly');
        const store = tx.objectStore(STORE_NAME);
        const req = store.getAll();
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
    });
}

export async function clearOfflineReports(): Promise<void> {
    const db = await initDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORE_NAME, 'readwrite');
        const store = tx.objectStore(STORE_NAME);
        const req = store.clear();
        req.onsuccess = () => resolve();
        req.onerror = () => reject(req.error);
    });
}

